import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  EmailNotificationHandler,
  resetEmailIdCounter,
} from '../../src/notifications/email-notification.handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let handler: EmailNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    handler = new EmailNotificationHandler(eventBus);
    resetEmailIdCounter();
  });

  describe('order:created email', () => {
    const makeOrderCreatedEvent = (overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent => ({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        ],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
      ...overrides,
    });

    it('should send confirmation email on order created', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.subject).toContain('order-1');
    });

    it('should include items and total in html body', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('$20.00');
      expect(email.htmlBody).toContain('<table>');
    });

    it('should include items and total in text body', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const email = handler.getSentEmails()[0]!;
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('$20.00');
      expect(email.textBody).toContain('Order Confirmation');
    });

    it('should include user name in the email body', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Alice');
      expect(email.textBody).toContain('Alice');
    });

    it('should include all items for multi-item orders', async () => {
      const event = makeOrderCreatedEvent({
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
      });

      await eventBus.emit(event);

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('Gadget');
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('Gadget x1');
      expect(email.htmlBody).toContain('$45.00');
    });
  });

  describe('order:status-changed email', () => {
    const makeStatusChangedEvent = (
      previousStatus: string,
      newStatus: string,
    ): OrderStatusChangedEvent => ({
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: newStatus as OrderStatusChangedEvent['order']['status'],
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus,
      newStatus,
      timestamp: new Date(),
    });

    it('should send status update email on status change', async () => {
      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('user-1');
      expect(emails[0]?.subject).toContain('order-1');
      expect(emails[0]?.subject).toContain('Confirmed');
    });

    it('should include previous and new status in html body', async () => {
      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));

      const email = handler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Confirmed');
      expect(email.htmlBody).toContain('Shipped');
    });

    it('should include previous and new status in text body', async () => {
      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));

      const email = handler.getSentEmails()[0]!;
      expect(email.textBody).toContain('Confirmed');
      expect(email.textBody).toContain('Shipped');
    });

    it('should handle all status transitions', async () => {
      const transitions: [string, string][] = [
        ['pending', 'confirmed'],
        ['confirmed', 'shipped'],
        ['shipped', 'delivered'],
        ['pending', 'cancelled'],
      ];

      for (const [from, to] of transitions) {
        await eventBus.emit(makeStatusChangedEvent(from, to));
      }

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(4);
      expect(emails[0]?.subject).toContain('Confirmed');
      expect(emails[1]?.subject).toContain('Shipped');
      expect(emails[2]?.subject).toContain('Delivered');
      expect(emails[3]?.subject).toContain('Cancelled');
    });
  });

  describe('email management', () => {
    it('should count sent emails', async () => {
      expect(handler.getSentEmailCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getSentEmailCount()).toBe(1);
    });

    it('should filter emails by recipient', async () => {
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(handler.getEmailsForRecipient('alice@example.com')).toHaveLength(1);
      expect(handler.getEmailsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear sent emails', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      handler.clearEmails();
      expect(handler.getSentEmailCount()).toBe(0);
    });

    it('should generate sequential email IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const emails = handler.getSentEmails();
      expect(emails[0]?.id).toBe('email-0001');
      expect(emails[1]?.id).toBe('email-0002');
    });
  });

  describe('coexistence with NotificationService', () => {
    it('should work alongside NotificationService on the same EventBus', async () => {
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      resetNotificationIdCounter();

      const sharedBus = new EventBus();
      const notificationService = new NotificationService(sharedBus);
      const emailHandler = new EmailNotificationHandler(sharedBus);
      resetEmailIdCounter();

      await sharedBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      // Both should have received the event
      expect(notificationService.getNotificationCount()).toBe(1);
      expect(emailHandler.getSentEmailCount()).toBe(1);

      // Email has richer formatting
      const email = emailHandler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('<h1>');
      expect(email.textBody).toBeTruthy();
    });
  });
});

